#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned long long A,B; scanf("%llu %llu", &A, &B);
        bool isPower = (B && (B & (B-1)) == 0ULL);
        puts(isPower?"Yes":"No");
    }
    return 0;
}

